<template><el-card><template #header>工具库</template><PageToolbar><el-input v-model="q" placeholder="搜索工具"/><template #actions><el-button type="primary">注册工具</el-button></template></PageToolbar><DataTable :data="filtered"><el-table-column prop="name" label="工具名称" min-width="180"/><el-table-column prop="type" label="工具类型"/><el-table-column prop="domain" label="业务域"/><el-table-column label="风险等级"><template #default="s"><StatusTag :value="s.row.risk"/></template></el-table-column><el-table-column prop="method" label="调用方式"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column prop="version" label="版本"/><el-table-column prop="successRate" label="成功率"/><el-table-column prop="avgLatency" label="平均耗时(ms)"/><el-table-column label="操作"><template #default="s"><el-button link>编辑</el-button><el-button link type="primary">测试</el-button><el-button link type="warning" @click="s.row.status='reviewing'">提交审核</el-button></template></el-table-column></DataTable></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { tools } from '@/mock/data'; import PageToolbar from '@/components/PageToolbar.vue'; import DataTable from '@/components/DataTable.vue'; import StatusTag from '@/components/StatusTag.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(tools))); const q=ref(''); const filtered=computed(()=>rows.value.filter(i=>!q.value||JSON.stringify(i).includes(q.value)));</script>
